85: // Normalize adjusts query parameters within the enforced boundaries.
86: // For example, limit is adjusted to be in the range (0, max].
87: // Given the limit is not supplied (0) it is set to the default limit.
88: func (q *QueryParams) Normalize() {
89: 	if q.Limit == 0 {
90: 		q.Limit = DefaultListLimit
